import React, { useState } from "react";

// Requires Bootstrap 5 CSS and Font Awesome to already be loaded in the app, e.g. in index.html:
// <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css">
// <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css">

// ---------------------------------------------------------------------------
// Config: one entry per side button. Each master has its own field set and
// its own seed rows, but they all render through the same list+form template
// so the whole panel reads as one system instead of seven bespoke screens.
// ---------------------------------------------------------------------------
const MASTERS = [
  {
    key: "schemeType",
    label: "Scheme type",
    icon: "fa fa-table-cells-large",
    listTitle: "Scheme type list",
    fields: [
      { key: "name", label: "Scheme type", placeholder: "Enter scheme type", required: true },
      { key: "localName", label: "Scheme type (local)", placeholder: "Enter scheme type in local language" },
    ],
    seed: [
      { id: 1, name: "Approval", localName: "" },
      { id: 2, name: "Permission", localName: "" },
      { id: 3, name: "Subsidy", localName: "" },
    ],
  },
  {
    key: "subsidyType",
    label: "Subsidy type",
    icon: "fa fa-sack-dollar",
    listTitle: "Subsidy type list",
    fields: [
      { key: "name", label: "Subsidy type", placeholder: "Enter subsidy type", required: true },
      { key: "localName", label: "Subsidy type (local)", placeholder: "Enter subsidy type in local language" },
    ],
    seed: [
      { id: 1, name: "Capital subsidy", localName: "" },
      { id: 2, name: "Interest subsidy", localName: "" },
    ],
  },
  {
    key: "schemeCategory",
    label: "Scheme category",
    icon: "fa fa-folder",
    listTitle: "Scheme category list",
    fields: [
      { key: "name", label: "Category name", placeholder: "Enter category name", required: true },
      { key: "code", label: "Category code", placeholder: "Enter category code" },
    ],
    seed: [
      { id: 1, name: "Agriculture", code: "AGR" },
      { id: 2, name: "Renewable energy", code: "REN" },
    ],
  },
  {
    key: "schemeSubCategory",
    label: "Scheme sub-category",
    icon: "fa fa-sitemap",
    listTitle: "Scheme sub-category list",
    fields: [
      { key: "name", label: "Sub-category name", placeholder: "Enter sub-category name", required: true },
      { key: "parent", label: "Parent category", placeholder: "Enter parent category" },
    ],
    seed: [{ id: 1, name: "Solar rooftop", parent: "Renewable energy" }],
  },
  {
    key: "schemeTechnology",
    label: "Scheme technology",
    icon: "fa fa-lightbulb",
    listTitle: "Scheme technology list",
    fields: [
      { key: "name", label: "Technology name", placeholder: "Enter technology name", required: true },
      { key: "description", label: "Description", placeholder: "Enter a short description" },
    ],
    seed: [
      { id: 1, name: "Photovoltaic", description: "" },
      { id: 2, name: "Wind turbine", description: "" },
    ],
  },
  {
    key: "documents",
    label: "Documents",
    icon: "fa fa-file-lines",
    listTitle: "Document list",
    fields: [
      { key: "name", label: "Document name", placeholder: "Enter document name", required: true },
      { key: "type", label: "Document type", placeholder: "e.g. Identity proof" },
    ],
    seed: [
      { id: 1, name: "Aadhaar card", type: "Identity proof" },
      { id: 2, name: "Land record", type: "Ownership proof" },
    ],
  },
  {
    key: "vendors",
    label: "Vendors",
    icon: "fa fa-truck",
    listTitle: "Vendor list",
    fields: [
      { key: "name", label: "Vendor name", placeholder: "Enter vendor name", required: true },
      { key: "contact", label: "Contact number", placeholder: "Enter contact number" },
    ],
    seed: [{ id: 1, name: "Sunrise Traders", contact: "" }],
  },
];

const emptyForm = (fields) => Object.fromEntries(fields.map((f) => [f.key, ""]));

export default function SchemeAdminPanel() {
  const [activeKey, setActiveKey] = useState(MASTERS[0].key);
  const [dataByKey, setDataByKey] = useState(() =>
    Object.fromEntries(MASTERS.map((m) => [m.key, m.seed]))
  );
  const [editingId, setEditingId] = useState(null);
  const [form, setForm] = useState(() => emptyForm(MASTERS[0].fields));

  const active = MASTERS.find((m) => m.key === activeKey);
  const rows = dataByKey[activeKey];

  function switchMaster(key) {
    const master = MASTERS.find((m) => m.key === key);
    setActiveKey(key);
    setEditingId(null);
    setForm(emptyForm(master.fields));
  }

  function handleFieldChange(key, value) {
    setForm((prev) => ({ ...prev, [key]: value }));
  }

  function handleSave() {
    const requiredField = active.fields.find((f) => f.required);
    if (requiredField && !form[requiredField.key]?.trim()) return;

    setDataByKey((prev) => {
      const list = prev[activeKey];
      if (editingId != null) {
        return {
          ...prev,
          [activeKey]: list.map((row) => (row.id === editingId ? { ...row, ...form } : row)),
        };
      }
      const nextId = list.length ? Math.max(...list.map((r) => r.id)) + 1 : 1;
      return { ...prev, [activeKey]: [...list, { id: nextId, ...form }] };
    });

    setEditingId(null);
    setForm(emptyForm(active.fields));
  }

  function handleCancel() {
    setEditingId(null);
    setForm(emptyForm(active.fields));
  }

  function handleEdit(row) {
    setEditingId(row.id);
    setForm(Object.fromEntries(active.fields.map((f) => [f.key, row[f.key] ?? ""])));
  }

  function handleDelete(id) {
    setDataByKey((prev) => ({
      ...prev,
      [activeKey]: prev[activeKey].filter((row) => row.id !== id),
    }));
    if (editingId === id) handleCancel();
  }

  return (
    <div className="card shadow-sm border-0 mb-3">
      {/* Frame header */}
      <div className="card-header bg-white d-flex align-items-center justify-content-between py-3">
        <h5 className="mb-0 fw-semibold">Scheme master data</h5>
        <small className="text-muted">
          Settings / Masters / <span className="text-secondary fw-medium">{active.label}</span>
        </small>
      </div>

      <div className="row g-0">
        {/* ---- LEFT NAV: 7 buttons ---- */}
        <div className="col-12 col-md-3 border-end bg-light">
          <div className="p-3">
            <div className="text-uppercase text-muted small fw-semibold mb-2" style={{ letterSpacing: "0.04em", fontSize: "0.7rem" }}>
              Add master entry
            </div>
            <div className="list-group list-group-flush">
              {MASTERS.map((m) => (
                <button
                  key={m.key}
                  type="button"
                  onClick={() => switchMaster(m.key)}
                  className={`list-group-item list-group-item-action border-0 rounded mb-1 d-flex align-items-center gap-2 ${
                    m.key === activeKey ? "active" : "bg-transparent"
                  }`}
                >
                  <i className={m.icon} style={{ width: 18, textAlign: "center" }}></i>
                  <span>{m.label}</span>
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* ---- LIST PANEL ---- */}
        <div className="col-12 col-md-5 border-end">
          <div className="border-bottom px-3 py-3">
            <h6 className="mb-0 fw-semibold">{active.listTitle}</h6>
            <small className="text-muted">
              {rows.length} {rows.length === 1 ? "entry" : "entries"}
            </small>
          </div>
          <div className="p-3">
            <div className="table-responsive">
              <table className="table table-hover align-middle mb-0">
                <thead>
                  <tr className="text-uppercase text-muted small">
                    <th style={{ width: 32 }}>#</th>
                    <th>{active.fields[0].label}</th>
                    <th className="text-end">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.map((row, i) => (
                    <tr key={row.id}>
                      <td className="text-muted">{i + 1}</td>
                      <td>{row.name}</td>
                      <td className="text-end">
                        <div className="btn-group btn-group-sm" role="group">
                          <button
                            type="button"
                            className="btn btn-outline-primary"
                            aria-label="Edit"
                            onClick={() => handleEdit(row)}
                          >
                            <i className="fa-solid fa-pen"></i>
                          </button>
                          <button
                            type="button"
                            className="btn btn-outline-secondary"
                            aria-label="View"
                            onClick={() => alert(JSON.stringify(row, null, 2))}
                          >
                            <i className="fa-solid fa-eye"></i>
                          </button>
                          <button
                            type="button"
                            className="btn btn-outline-danger"
                            aria-label="Delete"
                            onClick={() => handleDelete(row.id)}
                          >
                            <i className="fa-solid fa-trash"></i>
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                  {rows.length === 0 && (
                    <tr>
                      <td colSpan={3} className="text-center text-muted py-4">
                        No entries yet. Add one using the form on the right.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* ---- FORM PANEL ---- */}
        <div className="col-12 col-md-4">
          <div className="border-bottom px-3 py-3">
            <h6 className="mb-0 fw-semibold">
              {editingId != null ? `Edit ${active.label.toLowerCase()}` : `Add ${active.label.toLowerCase()}`}
            </h6>
            <small className="text-muted">Fill in the details below and save.</small>
          </div>
          <div className="p-3">
            <div className="row g-3">
              {active.fields.map((f) => (
                <div className="col-12" key={f.key}>
                  <label className="form-label small fw-medium text-secondary">
                    {f.label}
                    {f.required && <span className="text-danger ms-1">*</span>}
                  </label>
                  <input
                    type="text"
                    className="form-control"
                    placeholder={f.placeholder}
                    value={form[f.key] ?? ""}
                    onChange={(e) => handleFieldChange(f.key, e.target.value)}
                  />
                </div>
              ))}
            </div>

            <div className="d-flex justify-content-end gap-2 mt-4 pt-3 border-top">
              <button type="button" className="btn btn-outline-secondary" onClick={handleCancel}>
                <i className="fa-solid fa-xmark me-1"></i>
                Cancel
              </button>
              <button type="button" className="btn btn-primary" onClick={handleSave}>
                <i className={`fa-solid ${editingId != null ? "fa-check" : "fa-plus"} me-1`}></i>
                {editingId != null ? "Update" : "Save"}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
